import json
import sys
from pathlib import Path

import pandas as pd
from clearml import Dataset, Task


PROJECT_NAME = "three-lifes"
TASK_NAME = "upload-ollama-output-dataset"
DATASET_PROJECT = "three-lifes/datasets"
DATASET_NAME = "ollama-output-dataset"
DATASET_VERSION = "1.0.0"
DATASET_DESCRIPTION = (
    "CSV outputs generated by the Ollama-based article ingestion, v2 summarisation, "
    "and summary evaluation pipeline."
)


def get_paths() -> tuple[Path, Path]:
    project_root = Path(__file__).resolve().parent.parent
    data_dir = project_root / "data" / "ollama_output"

    if not data_dir.exists():
        raise FileNotFoundError(f"Data directory not found: {data_dir}")

    return project_root, data_dir


def get_csv_files(data_dir: Path) -> list[Path]:
    csv_files = sorted(
        path for path in data_dir.iterdir()
        if path.is_file() and path.suffix.lower() == ".csv"
    )

    if not csv_files:
        raise FileNotFoundError(f"No CSV files found in: {data_dir}")

    return csv_files


def load_dataframe(csv_path: Path) -> pd.DataFrame:
    return pd.read_csv(csv_path)


def build_schema(df: pd.DataFrame) -> dict[str, str]:
    schema: dict[str, str] = {}
    for column, dtype in df.dtypes.items():
        schema[column] = str(dtype)
    return schema


def build_file_metadata(csv_files: list[Path]) -> list[dict]:
    files_metadata: list[dict] = []

    for csv_path in csv_files:
        df = load_dataframe(csv_path)
        files_metadata.append(
            {
                "file_name": csv_path.name,
                "format": "csv",
                "row_count": int(len(df)),
                "column_count": int(len(df.columns)),
                "fields": list(df.columns),
                "schema": build_schema(df),
            }
        )

    return files_metadata


def build_dataset_metadata(csv_files: list[Path], files_metadata: list[dict]) -> dict:
    total_rows = sum(file_meta["row_count"] for file_meta in files_metadata)

    return {
        "source": "NewsAPI article collection pipeline with Ollama summarisation/evaluation outputs",
        "format": "multiple_csv_files",
        "file_count": len(csv_files),
        "total_row_count": int(total_rows),
        "files": files_metadata,
    }


def upload_dataset(data_dir: Path, metadata: dict, csv_files: list[Path]) -> Dataset:
    task = Task.init(
        project_name="three-lifes",
        task_name="upload-ollama-output-dataset",
        task_type=Task.TaskTypes.data_processing,
    )

    dataset = Dataset.create(
        dataset_project=DATASET_PROJECT,
        dataset_name=DATASET_NAME,
        dataset_version=DATASET_VERSION,
        use_current_task=True,
        description=DATASET_DESCRIPTION,
    )

    for csv_path in csv_files:
        dataset.add_files(path=str(csv_path))

    dataset.set_metadata(metadata)

    task.connect(
        {
            "dataset_name": DATASET_NAME,
            "dataset_version": DATASET_VERSION,
            "dataset_project": DATASET_PROJECT,
            "source": metadata["source"],
            "file_count": metadata["file_count"],
            "total_row_count": metadata["total_row_count"],
            "files": metadata["files"],
        }
    )

    for csv_path in csv_files:
        task.get_logger().report_table(
            title="Dataset Preview",
            series=csv_path.name,
            csv=str(csv_path),
        )

    dataset.upload(show_progress=True)
    dataset.finalize()

    return dataset


def save_submission_info(project_root: Path, dataset: Dataset, metadata: dict) -> Path:
    output_path = project_root / "data" / "ollama_output" / "clearml_dataset_info.json"

    info = {
        "dataset_name": DATASET_NAME,
        "dataset_version": DATASET_VERSION,
        "dataset_project": DATASET_PROJECT,
        "dataset_id": dataset.id,
        "file_count": metadata["file_count"],
        "total_row_count": metadata["total_row_count"],
        "source": metadata["source"],
        "files": metadata["files"],
    }

    with output_path.open("w", encoding="utf-8") as f:
        json.dump(info, f, indent=2, ensure_ascii=False)

    return output_path


def main() -> int:
    try:
        project_root, data_dir = get_paths()
        csv_files = get_csv_files(data_dir)
        files_metadata = build_file_metadata(csv_files)
        metadata = build_dataset_metadata(csv_files, files_metadata)
        dataset = upload_dataset(data_dir, metadata, csv_files)
        info_path = save_submission_info(project_root, dataset, metadata)

        print("ClearML dataset uploaded successfully.")
        print(f"Dataset name: {DATASET_NAME}")
        print(f"Dataset version: {DATASET_VERSION}")
        print(f"Dataset ID: {dataset.id}")
        print(f"CSV files uploaded: {metadata['file_count']}")
        print(f"Total rows across all CSV files: {metadata['total_row_count']}")
        print("Uploaded files:")
        for file_meta in metadata["files"]:
            print(
                f"  - {file_meta['file_name']} "
                f"(rows={file_meta['row_count']}, cols={file_meta['column_count']})"
            )
        print(f"Submission info saved to: {info_path}")
        return 0

    except FileNotFoundError as exc:
        print(f"Error: {exc}")
        return 1
    except Exception as exc:
        print(f"Error: failed to upload dataset to ClearML: {exc}")
        return 1


if __name__ == "__main__":
    sys.exit(main())